// ═══════════════════════════════════════════════════════════════
// STRUCTURATION DES DONNÉES PAR DESTINATAIRE — XRAPRH (Rapports RH)
// Niveaux : SALARIE / SUPERIEUR / FARHAT / BAALLAH / DGA / PDG
// ═══════════════════════════════════════════════════════════════

const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📋 STRUCTURATION NOTIFICATIONS - RAPPORTS RH XRAPRH');
console.log('═══════════════════════════════════════════════════');
console.log(`Lignes reçues: ${items.length}`);

const notifications = {};

items.forEach(item => {
  const data = item.json;
  let destinatairePrincipal;
  let codeDestinataire;
  let typeDestinataire;

  switch (data.niveau_escalade) {

    case 'PDG':
      destinatairePrincipal = {
        code:      data.code_pdg,
        nom:       data.nom_pdg,
        prenom:    data.prenom_pdg,
        email:     data.email_pdg,
        telephone: data.tel_pdg,
        chat_id:   data.chat_id_pdg,
        langue:    data.langue_pdg || 'FRA',
        bot:       data.bot_pdg
      };
      codeDestinataire = data.code_pdg;
      typeDestinataire = 'PDG';
      break;

    case 'DGA':
      destinatairePrincipal = {
        code:      data.code_dga,
        nom:       data.nom_dga,
        prenom:    data.prenom_dga,
        email:     data.email_dga,
        telephone: data.tel_dga,
        chat_id:   data.chat_id_dga,
        langue:    data.langue_dga || 'FRA',
        bot:       data.bot_dga
      };
      codeDestinataire = data.code_dga;
      typeDestinataire = 'DGA';
      break;

    case 'SUPERIEUR':
      destinatairePrincipal = {
        code:      data.code_superieur,
        nom:       data.nom_superieur,
        prenom:    data.prenom_superieur,
        email:     data.email_superieur,
        telephone: data.tel_superieur,
        chat_id:   data.chat_id_superieur,
        langue:    data.langue_superieur || 'FRA',
        bot:       data.bot_superieur
      };
      codeDestinataire = data.code_superieur;
      typeDestinataire = 'SUPERIEUR';
      break;

    case 'SALARIE':
      destinatairePrincipal = {
        code:      data.code_createur,
        nom:       data.nom_createur,
        prenom:    data.prenom_createur,
        email:     data.email_createur,
        telephone: data.tel_createur,
        chat_id:   data.chat_id_createur,
        langue:    data.langue_createur || 'FRA',
        bot:       data.bot_createur
      };
      codeDestinataire = data.code_createur;
      typeDestinataire = 'SALARIE';
      break;

    case 'FARHAT':
      destinatairePrincipal = {
        code:      data.code_farhat,
        nom:       data.nom_farhat,
        prenom:    data.prenom_farhat,
        email:     data.email_farhat,
        telephone: data.tel_farhat,
        chat_id:   data.chat_id_farhat,
        langue:    data.langue_farhat || 'FRA',
        bot:       data.bot_farhat
      };
      codeDestinataire = data.code_farhat;
      typeDestinataire = 'FARHAT';
      break;

    case 'BAALLAH':
      destinatairePrincipal = {
        code:      data.code_baallah,
        nom:       data.nom_baallah,
        prenom:    data.prenom_baallah,
        email:     data.email_baallah,
        telephone: data.tel_baallah,
        chat_id:   data.chat_id_baallah,
        langue:    data.langue_baallah || 'FRA',
        bot:       data.bot_baallah
      };
      codeDestinataire = data.code_baallah;
      typeDestinataire = 'BAALLAH';
      break;

    default:
      console.log(`⏭️  Rapport ${data.num_rapport} ignoré (niveau: ${data.niveau_escalade})`);
      return;
  }

  const cleDestinataire = `${typeDestinataire}_${codeDestinataire}`;

  if (!notifications[cleDestinataire]) {
    notifications[cleDestinataire] = {
      destinataire_principal: destinatairePrincipal,
      type_destinataire: typeDestinataire,
      niveau_escalade:   data.niveau_escalade,

      // ── Profils complets ──
      createur: {
        code:      data.code_createur,
        nom:       data.nom_createur,
        prenom:    data.prenom_createur,
        email:     data.email_createur,
        telephone: data.tel_createur,
        chat_id:   data.chat_id_createur,
        langue:    data.langue_createur || 'FRA',
        bot:       data.bot_createur
      },
      salarie: {
        code:      data.code_salarie,
        nom:       data.nom_salarie,
        prenom:    data.prenom_salarie,
        email:     data.email_salarie,
        telephone: data.tel_salarie,
        chat_id:   data.chat_id_createur,
        langue:    data.langue_createur || 'FRA',
        bot:       data.bot_createur
      },
      superieur: {
        code:      data.code_superieur,
        nom:       data.nom_superieur,
        prenom:    data.prenom_superieur,
        email:     data.email_superieur,
        telephone: data.tel_superieur,
        chat_id:   data.chat_id_superieur,
        langue:    data.langue_superieur || 'FRA',
        bot:       data.bot_superieur
      },
      pdg: {
        code:      data.code_pdg,
        nom:       data.nom_pdg,
        prenom:    data.prenom_pdg,
        email:     data.email_pdg,
        telephone: data.tel_pdg,
        chat_id:   data.chat_id_pdg,
        langue:    data.langue_pdg || 'FRA',
        bot:       data.bot_pdg
      },
      dga: {
        code:      data.code_dga,
        nom:       data.nom_dga,
        prenom:    data.prenom_dga,
        email:     data.email_dga,
        telephone: data.tel_dga,
        chat_id:   data.chat_id_dga,
        langue:    data.langue_dga || 'FRA',
        bot:       data.bot_dga
      },
      farhat: {
        code:      data.code_farhat,
        nom:       data.nom_farhat,
        prenom:    data.prenom_farhat,
        email:     data.email_farhat,
        telephone: data.tel_farhat,
        chat_id:   data.chat_id_farhat,
        langue:    data.langue_farhat || 'FRA',
        bot:       data.bot_farhat
      },
      baallah: {
        code:      data.code_baallah,
        nom:       data.nom_baallah,
        prenom:    data.prenom_baallah,
        email:     data.email_baallah,
        telephone: data.tel_baallah,
        chat_id:   data.chat_id_baallah,
        langue:    data.langue_baallah || 'FRA',
        bot:       data.bot_baallah
      },

      rapports: []
    };
  }

  // ── Données spécifiques au rapport RH ──
  notifications[cleDestinataire].rapports.push({
    num_rapport:           data.num_rapport,
    date_rapport:          data.date_rapport,
    date_creation:         data.date_creation,
    date_controle:         data.date_controle,
    date_limite:           data.date_limite,
    jours_depuis_creation: data.jours_depuis_creation,
    jours_restants:        data.jours_restants,
    delai_int:             data.delai_int,
    type_rapport:          data.type_rapport,
    cadre_juridique:       data.cadre_juridique,
    concernes:             data.concernes,
    nom_prenom_sujet:      data.nom_prenom_sujet,
    fonction_salarie:      data.fonction_salarie,
    adresse_salarie:       data.adresse_salarie,
    matricule_salarie:     data.matricule_salarie,
    salarie_concerne: {
      code:      data.code_salarie,
      matricule: data.matricule_salarie,
      nom:       data.nom_salarie,
      prenom:    data.prenom_salarie,
      email:     data.email_salarie,
      telephone: data.tel_salarie,
      fonction:  data.fonction_salarie
    }
  });
});

const resultats = Object.values(notifications).map(notif => {
  const totalRapports = notif.rapports.length;
  const joursMin      = Math.min(...notif.rapports.map(r => r.jours_restants));
  const joursMax      = Math.max(...notif.rapports.map(r => r.jours_restants));
  const delaiTotal    = parseInt(notif.rapports[0]?.delai_int) || 10;
  const seuilDga      = Math.floor(delaiTotal / 2);

  // ── Comptage par type de rapport ──
  const typesCount = {};
  notif.rapports.forEach(r => {
    const t = r.type_rapport || 'Non défini';
    typesCount[t] = (typesCount[t] || 0) + 1;
  });

  // ── CC Email & Telegram ──
  let emailCC    = [];
  let telegramCC = [];

  if (notif.type_destinataire === 'PDG') {
    if (notif.superieur?.email)   emailCC.push(notif.superieur.email);
    if (notif.createur?.email)    emailCC.push(notif.createur.email);
    if (notif.superieur?.chat_id) telegramCC.push({
      chat_id: notif.superieur.chat_id, bot: notif.superieur.bot,
      langue: notif.superieur.langue,
      nom: `${notif.superieur.prenom} ${notif.superieur.nom}`
    });
    if (notif.createur?.chat_id) telegramCC.push({
      chat_id: notif.createur.chat_id, bot: notif.createur.bot,
      langue: notif.createur.langue,
      nom: `${notif.createur.prenom} ${notif.createur.nom}`
    });
  } else if (notif.type_destinataire === 'SUPERIEUR') {
    if (notif.createur?.email)   emailCC.push(notif.createur.email);
    if (notif.createur?.chat_id) telegramCC.push({
      chat_id: notif.createur.chat_id, bot: notif.createur.bot,
      langue: notif.createur.langue,
      nom: `${notif.createur.prenom} ${notif.createur.nom}`
    });
  }

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire:      notif.type_destinataire,
    niveau_escalade:        notif.niveau_escalade,
    email_cc:               emailCC.length   > 0 ? emailCC.join(',') : null,
    telegram_cc:            telegramCC.length > 0 ? telegramCC        : null,
    createur:  notif.createur,
    salarie:   notif.salarie,
    superieur: notif.superieur,
    pdg:       notif.pdg,
    dga:       notif.dga,
    farhat:    notif.farhat,
    baallah:   notif.baallah,
    rapports:  notif.rapports,
    statistiques: {
      total_rapports: totalRapports,
      jours_min:      joursMin,
      jours_max:      joursMax,
      priorite:       notif.niveau_escalade,
      delai_total:    delaiTotal,
      seuil_dga:      seuilDga,
      types_count:    typesCount
    },
    meta: {
      date_traitement:       new Date().toISOString(),
      langue_message:        notif.destinataire_principal.langue || 'FRA',
      peut_envoyer_email:    !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id
    }
  };
});

console.log(`\n✅ Notifications structurées: ${resultats.length}`);
['PDG','DGA','BAALLAH','FARHAT','SUPERIEUR','SALARIE'].forEach(t => {
  console.log(`  - ${t}: ${resultats.filter(r => r.type_destinataire === t).length}`);
});
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

