function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const dest = data.destinataire_principal;
  const stats = data.statistiques;
  const rapports = data.rapports;

  const sujet = (T.sujet_email[data.type_destinataire] || T.sujet_email.SALARIE)
              + ` - ${stats.total_rapports} rapport(s)`;

  // ── Corps email ──
  let body = `${T.salutation} ${dest.prenom} ${dest.nom},\n\n`;
  body += `${T.introduction[data.type_destinataire]}\n\n`;
  body += `══════════════════════════════════════════════════════════\n`;
  body += `📊 ${T.section_stats}\n`;
  body += `══════════════════════════════════════════════════════════\n\n`;
  body += `${getEmoji(stats.jours_min)} Niveau d'escalade : ${data.niveau_escalade}\n`;
  body += `${T.total} : ${stats.total_rapports}\n`;
  body += `${T.delai_min} : ${stats.jours_min} ${T.jours}\n`;
  body += `${T.delai_total} : ${stats.delai_total} ${T.jours}\n`;
  if (['DGA','BAALLAH'].includes(data.type_destinataire)) {
    body += `${T.seuil_dga} : ${stats.seuil_dga} ${T.jours}\n`;
  }

  // Répartition par type
  if (stats.types_count && Object.keys(stats.types_count).length > 0) {
    body += `\n📂 ${T.types_repartition} :\n`;
    Object.entries(stats.types_count).forEach(([type, count]) => {
      body += `   • ${type} : ${count}\n`;
    });
  }

  body += `\n══════════════════════════════════════════════════════════\n`;
  body += `📋 ${T.section_rapports}\n`;
  body += `══════════════════════════════════════════════════════════\n\n`;

  rapports.forEach((rap, i) => {
      body += `${i + 1}. ${getEmoji(rap.jours_restants)} ${rap.num_rapport}\n`;
      if (rap.type_rapport) body += `   🏷️  ${T.type_rapport} : ${rap.type_rapport}\n`;
      body += `   📅 ${T.date_rapport} : ${formaterDate(rap.date_rapport, langue)}\n`;
      body += `   🗂️  ${T.date_creation} : ${formaterDateHeure(rap.date_creation, langue)}\n`;
      // ✅ Salarié concerné
      body += `   👤 ${T.salarie_concerne} : ${rap.salarie_concerne.prenom} ${rap.salarie_concerne.nom}`;
      if (rap.salarie_concerne.matricule) body += ` (${T.matricule}: ${rap.salarie_concerne.matricule})`;
      body += `\n`;
      if (rap.salarie_concerne.fonction) body += `   💼 ${T.fonction} : ${rap.salarie_concerne.fonction}\n`;
      if (rap.nom_prenom_sujet)  body += `   📌 ${T.sujet} : ${rap.nom_prenom_sujet}\n`;
      if (rap.cadre_juridique)   body += `   ⚖️  ${T.cadre_juridique} : ${rap.cadre_juridique}\n`;
      if (rap.concernes)         body += `   👥 ${T.concernes} : ${rap.concernes}\n`;
      body += `   ⏰ ${T.delai_label} : ${rap.jours_restants} ${T.jours} ${T.restant} (${T.limite} : ${formaterDate(rap.date_limite, langue)})\n`;
      // ✅ Créateur du rapport
      body += `   ─────────────────────────────────────\n`;
      body += `   ✍️  ${T.createur_label} : ${data.createur.prenom || ''} ${data.createur.nom || ''} (${data.createur.code || rap.user_createur || 'N/A'})\n`;
      if (data.createur.email)     body += `   ✉️  ${T.email_createur_label} : ${data.createur.email}\n`;
      if (data.createur.telephone) body += `   📞 ${T.tel_createur_label} : ${data.createur.telephone}\n`;
      if (rap.jours_restants <= 2) body += `   🚨 ${T.urgent}\n`;
      body += `\n`;
  });

  body += `══════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    body += `🚨 ${T.action_requise} : ${T.urgent}\n`;
  } else if (['DGA','BAALLAH'].includes(data.type_destinataire)) {
    body += `📌 ${T.instruction_dga}\n`;
  } else {
    body += `📌 ${T.instruction}\n`;
  }
  body += `══════════════════════════════════════════════════════════\n\n`;
  body += `${T.cordialement},\n\n${T.signature}\n\n`;
  body += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  body += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  if (data.type_destinataire === 'PDG') body += `🔴 Notification URGENTE envoyée au PDG\n`;
  if (data.type_destinataire === 'DGA') body += `🟠 Notification DGA (seuil mi-délai: ${stats.seuil_dga}j)\n`;
  body += `${T.ne_pas_repondre}\n`;

  // ── Telegram ──
  let tg = `${getEmoji(stats.jours_min)} *${T.sujet_email[data.type_destinataire]}*\n`;
  tg += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  tg += `👤 *${dest.prenom} ${dest.nom}*\n\n`;
  tg += `📊 *${T.section_stats}*\n`;
  tg += `${T.total} : *${stats.total_rapports}*\n`;
  tg += `${T.delai_min} : *${stats.jours_min} ${T.jours}*\n`;

  // Types en Telegram
  if (stats.types_count && Object.keys(stats.types_count).length > 0) {
    tg += `\n📂 ${T.types_repartition} :\n`;
    Object.entries(stats.types_count).forEach(([type, count]) => {
      tg += `   • ${type} : ${count}\n`;
    });
  }
  tg += `\n📋 *${T.section_rapports}*\n\n`;

  rapports.slice(0, 5).forEach((rap, i) => {
      tg += `${i + 1}. ${getEmoji(rap.jours_restants)} *${rap.num_rapport}*\n`;
      if (rap.type_rapport) tg += `   🏷️ ${rap.type_rapport}\n`;
      tg += `   👤 ${rap.salarie_concerne.prenom} ${rap.salarie_concerne.nom}\n`;
      if (rap.nom_prenom_sujet) tg += `   📌 ${rap.nom_prenom_sujet}\n`;
      tg += `   ⏰ ${rap.jours_restants} ${T.jours} ${T.restant}\n`;
      // ✅ Créateur
      tg += `   ✍️ *${T.createur_label}* : ${data.createur.prenom || ''} ${data.createur.nom || ''}\n`;
      if (data.createur.telephone) tg += `   📞 ${data.createur.telephone}\n`;
      tg += `\n`;
  });

  if (rapports.length > 5) tg += `... et ${rapports.length - 5} autre(s) rapport(s)\n\n`;
  if (stats.jours_min <= 2) tg += `🚨 *${T.urgent}*\n`;

  return {
    email:    { subject: sujet, body },
    telegram: { text: tg, parse_mode: 'Markdown' }
  };
}

// ─────────────────────────────────────────────────────────────
// MESSAGE CC
// ─────────────────────────────────────────────────────────────
function genererMessageCC(data, destinataireCC, typeDestinatairePrincipal) {
  const langue = destinataireCC.langue || data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const stats = data.statistiques;
  const rapports = data.rapports;
  const destPrincipal = data.destinataire_principal;

  const labels = { PDG: 'le PDG', DGA: 'le DGA', SUPERIEUR: 'votre supérieur(e)', FARHAT: 'le Responsable RH', BAALLAH: 'la Direction' };
  const label = labels[typeDestinatairePrincipal] || typeDestinatairePrincipal;

  const sujet = `${T.copie_info} - ${T.sujet_email[typeDestinatairePrincipal]} - ${stats.total_rapports} rapport(s)`;

  let body = `${T.salutation} ${destinataireCC.prenom} ${destinataireCC.nom},\n\n`;
  body += `Un message d'alerte concernant les rapports RH non attachés a été envoyé à ${label} ${destPrincipal.prenom} ${destPrincipal.nom}.\n\n`;
  body += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade} | ${T.total}: ${stats.total_rapports} | ${T.delai_min}: ${stats.jours_min} ${T.jours}\n\n`;
  body += `══════════════════════════════════════════════════════════\n`;
  body += `📋 ${T.section_rapports}\n`;
  body += `══════════════════════════════════════════════════════════\n\n`;

  rapports.forEach((rap, i) => {
      body += `${i + 1}. ${getEmoji(rap.jours_restants)} ${rap.num_rapport}\n`;
      if (rap.type_rapport) body += `   🏷️  ${T.type_rapport}: ${rap.type_rapport}\n`;
      body += `   👤 ${rap.salarie_concerne.prenom} ${rap.salarie_concerne.nom}\n`;
      if (rap.nom_prenom_sujet) body += `   📌 ${T.sujet}: ${rap.nom_prenom_sujet}\n`;
      body += `   ⏰ ${rap.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(rap.date_limite, langue)})\n`;
      // ✅ Créateur
      body += `   ✍️  ${T.createur_label} : ${data.createur.prenom || ''} ${data.createur.nom || ''} (${data.createur.code || 'N/A'})\n`;
      if (data.createur.email)     body += `   ✉️  ${T.email_createur_label} : ${data.createur.email}\n`;
      if (data.createur.telephone) body += `   📞 ${T.tel_createur_label} : ${data.createur.telephone}\n`;
      body += `\n`;
  });

  body += `Veuillez prendre les mesures nécessaires pour traiter ces rapports dans les délais impartis.\n\n`;
  body += `${T.cordialement},\n\n${T.signature}\n`;
  body += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  body += `🤖 ${T.message_auto} | ${T.copie_info} | ${T.ne_pas_repondre}\n`;

  let tg = `${T.copie_info}\n━━━━━━━━━━━━━━━━━━━━━\n\n`;
  tg += `${T.salutation} *${destinataireCC.prenom} ${destinataireCC.nom}*,\n\n`;
  tg += `Un message a été envoyé à *${destPrincipal.prenom} ${destPrincipal.nom}* (${label}).\n\n`;
  tg += `📊 ${T.total}: *${stats.total_rapports}* | ⏰ *${stats.jours_min} ${T.jours}*\n\n`;

  rapports.slice(0, 3).forEach((rap, i) => {
      tg += `${i + 1}. ${getEmoji(rap.jours_restants)} *${rap.num_rapport}*\n`;
      if (rap.type_rapport) tg += `   🏷️ ${rap.type_rapport}\n`;
      tg += `   👤 ${rap.salarie_concerne.prenom} ${rap.salarie_concerne.nom}\n`;
      tg += `   ⏰ ${rap.jours_restants} ${T.jours} ${T.restant}\n`;
      // ✅ Créateur
      tg += `   ✍️ *${T.createur_label}* : ${data.createur.prenom || ''} ${data.createur.nom || ''}\n`;
      tg += `\n`;
  });

  return {
    email:    { subject: sujet, body },
    telegram: { text: tg, parse_mode: 'Markdown' }
  };
}

// ─────────────────────────────────────────────────────────────
// DISPATCH
// ─────────────────────────────────────────────────────────────
const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messages = genererMessagePrincipal(data);

  // Message principal
  results.push({
    json: {
      ...data,
      messages,
      type_envoi:         'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }
  });

  // CC SUPERIEUR → copie au créateur
  if (data.type_destinataire === 'SUPERIEUR' && data.createur?.chat_id) {
    const messagesCC = genererMessageCC(data, data.createur, 'SUPERIEUR');
    results.push({ json: {
      ...data, messages: messagesCC, type_envoi: 'CC',
      destinataire_final: data.createur, cc_pour_profil: 'CREATEUR',
      meta: { ...data.meta, langue_message: data.createur.langue || 'FRA', date_generation: new Date().toISOString() }
    }});
  }

  // CC PDG → copie supérieur + créateur
  if (data.type_destinataire === 'PDG') {
    if (data.superieur?.chat_id) {
      const msgCCSup = genererMessageCC(data, data.superieur, 'PDG');
      results.push({ json: {
        ...data, messages: msgCCSup, type_envoi: 'CC',
        destinataire_final: data.superieur, cc_pour_profil: 'SUPERIEUR',
        meta: { ...data.meta, langue_message: data.superieur.langue || 'FRA', date_generation: new Date().toISOString() }
      }});
    }
    if (data.createur?.chat_id) {
      const msgCCSal = genererMessageCC(data, data.createur, 'PDG');
      results.push({ json: {
        ...data, messages: msgCCSal, type_envoi: 'CC',
        destinataire_final: data.createur, cc_pour_profil: 'CREATEUR',
        meta: { ...data.meta, langue_message: data.createur.langue || 'FRA', date_generation: new Date().toISOString() }
      }});
    }
  }
});

console.log(`\n📧 Messages générés: ${results.length}`);
console.log(`  - Principaux: ${results.filter(r => r.json.type_envoi === 'PRINCIPAL').length}`);
console.log(`  - CC:         ${results.filter(r => r.json.type_envoi === 'CC').length}`);
console.log('═══════════════════════════════════════════════════\n');

return results;
